SELECT id, dept_name, business_type, amount, record_count, create_time, remark
FROM business_record

    
        dept_name LIKE CONCAT('%',#{query.deptName},'%')
    
    
        business_type = #{query.businessType}
    
    
        create_time >= #{query.startTime}
    
    
        create_time <= #{query.endTime}
    

ORDER BY create_time DESC
LIMIT #{offset}, #{pageSize}

SELECT COUNT(1)
FROM business_record

    
        dept_name LIKE CONCAT('%',#{query.deptName},'%')
    
    
        business_type = #{query.businessType}
    
    
        create_time >= #{query.startTime}
    
    
        create_time <= #{query.endTime}
